¡Hola Alejo!  
A continuación tienes el código completo para cada una de las herramientas que solicitaste.  
Cada archivo seguirá la estructura requerida (tool_definition + `run`), tendrá manejo de errores robusto y un `print` con el nombre de la herramienta para el logging.

**1. web_search.py** – Búsqueda web
```python
# web_search.py

import requests
import json
from typing import Any

tool_definition = {
    "type": "function",
    "function": {
        "name": "web_search",
        "description": "Realiza una búsqueda en la web usando la API de DuckDuckGo y devuelve los resultados más relevantes.",
        "parameters": {
            "type": "object",
            "properties": {
                "query": {
                    "type": "string",
                    "description": "Texto a buscar en la web."
                }
            },
            "required": ["query"]
        }
    }
}

def run(query: str) -> str:
    """Realiza una búsqueda web y devuelve los títulos y enlaces de los primeros resultados."""
    print(" ⚙️ Herramienta llamada: web_search")
    try:
        if not query:
            return "Error en web_search: no se proporcionó ninguna consulta."

        # Usamos DuckDuckGo Instant Answer API (sin API Key)
        url = "https://api.duckduckgo.com/"
        params = {
            "q": query,
            "format": "json",
            "no_html": 1,
            "skip_disambig": 1
        }
        resp = requests.get(url, params=params, timeout=10)
        resp.raise_for_status()
        data = resp.json()

        results = []
        if "RelatedTopics" in data:
            for topic in data["RelatedTopics"]:
                if "Text" in topic and "FirstURL" in topic:
                    results.append({"title": topic["Text"], "url": topic["FirstURL"]})
                # En la API hay subestructuras anidadas
                if "Topics" in topic:
                    for sub in topic["Topics"]:
                        if "Text" in sub and "FirstURL" in sub:
                            results.append({"title": sub["Text"], "url": sub["FirstURL"]})
        if not results:
            return "No se encontraron resultados para la consulta."

        # Limitar a los primeros 5 resultados
        top_results = results[:5]
        return json.dumps(top_results, ensure_ascii=False, indent=2)

    except Exception as e:
        err = f"Error en web_search: {str(e)}"
        print(err)
        return err
```

**2. seo.py** – Análisis de SEO
```python
# seo.py

import requests
import re
from typing import Any

tool_definition = {
    "type": "function",
    "function": {
        "name": "seo",
        "description": "Analiza los elementos SEO básicos de una página web: título, meta descripción y presencia de H1.",
        "parameters": {
            "type": "object",
            "properties": {
                "url": {
                    "type": "string",
                    "description": "URL de la página a analizar."
                }
            },
            "required": ["url"]
        }
    }
}

def run(url: str) -> str:
    """Descarga la página y devuelve un resumen de SEO (title, meta description, H1)."""
    print(" ⚙️ Herramienta llamada: seo")
    try:
        if not url:
            return "Error en seo: no se proporcionó una URL."

        resp = requests.get(url, timeout=10)
        resp.raise_for_status()
        html = resp.text

        # Título
        title_match = re.search(r"<title>(.*?)</title>", html, re.IGNORECASE | re.DOTALL)
        title = title_match.group(1).strip() if title_match else "No encontrado"

        # Meta descripción
        meta_match = re.search(r'<meta\s+name=["\']description["\']\s+content=["\'](.*?)["\']', html, re.IGNORECASE | re.DOTALL)
        meta_desc = meta_match.group(1).strip() if meta_match else "No encontrada"

        # Primer H1
        h1_match = re.search(r"<h1[^>]*>(.*?)</h1>", html, re.IGNORECASE | re.DOTALL)
        h1 = h1_match.group(1).strip() if h1_match else "No encontrado"

        result = {
            "title": title,
            "meta_description": meta_desc,
            "first_h1": h1
        }
        return str(result)

    except Exception as e:
        err = f"Error en seo: {str(e)}"
        print(err)
        return err
```

**3. comment_code.py** – Comentario de código
```python
# comment_code.py

import ast
import astor  # Para convertir AST de vuelta a código con comentarios
from typing import Any

tool_definition = {
    "type": "function",
    "function": {
        "name": "commentary_code",
        "description": "Genera comentarios explicativos para cada función y clase dentro de un archivo Python.",
        "parameters": {
            "type": "object",
            "properties": {
                "file_path": {
                    "type": "string",
                    "description": "Ruta del archivo Python a comentar."
                }
            },
            "required": ["file_path"]
        }
    }
}

class CommentGenerator(ast.NodeVisitor):
    def __init__(self, source: str):
        self.source = source
        self.lines = source.splitlines()
        self.comments = []

    def add_comment(self, node, comment):
        # Encuentra la línea donde comienza la definición
        lineno = node.lineno - 1  # 0‑based
        # Inserta comentario justo antes de la línea
        self.comments.append((lineno, comment))

    def visit_FunctionDef(self, node):
        comment = f"\"\"\"Funcion {node.name}: {node.args.args[0].arg if node.args.args else ''}\"\"\""
        self.add_comment(node, comment)
        self.generic_visit(node)

    def visit_ClassDef(self, node):
        comment = f"\"\"\"Clase {node.name}\"\"\""
        self.add_comment(node, comment)
        self.generic_visit(node)

    def apply(self):
        # Ordenamos por línea descendente para no cambiar índices
        for lineno, comment in sorted(self.comments, key=lambda x: x[0], reverse=True):
            self.lines.insert(lineno, comment)
        return "\n".join(self.lines)

def run(file_path: str) -> str:
    """Lee un archivo Python, añade comentarios descriptivos y devuelve el código comentado."""
    print(" ⚙️ Herramienta llamada: commentary_code")
    try:
        if not file_path:
            return "Error en commentary_code: no se proporcionó la ruta del archivo."

        with open(file_path, "r", encoding="utf-8") as f:
            source = f.read()

        tree = ast.parse(source)
        generator = CommentGenerator(source)
        generator.visit(tree)
        commented_source = generator.apply()

        return commented_source

    except Exception as e:
        err = f"Error en commentary_code: {str(e)}"
        print(err)
        return err
```

**4. get_stock_price.py** – Precio de acciones/cripto
```python
# get_stock_price.py

import requests
from typing import Any

tool_definition = {
    "type": "function",
    "function": {
        "name": "get_stock_price",
        "description": "Obtiene el precio actual de una acción o criptomoneda usando la API de Alpha Vantage (o Binance para cripto).",
        "parameters": {
            "type": "object",
            "properties": {
                "symbol": {
                    "type": "string",
                    "description": "Ticker de la acción (p. ej. AAPL) o símbolo de cripto (p. ej. BTCUSDT)."
                }
            },
            "required": ["symbol"]
        }
    }
}

def run(symbol: str) -> str:
    """Devuelve el precio de cierre más reciente para el símbolo dado."""
    print(" ⚙️ Herramienta llamada: get_stock_price")
    try:
        if not symbol:
            return "Error en get_stock_price: no se proporcionó el símbolo."

        # Si el símbolo termina en USDT o BTC, asumimos criptomoneda (Binance)
        if symbol.endswith("USDT") or symbol.endswith("BTC"):
            url = f"https://api.binance.com/api/v3/ticker/price?symbol={symbol}"
            resp = requests.get(url, timeout=10)
            resp.raise_for_status()
            data = resp.json()
            price = data.get("price")
            return f"Precio de {symbol} en Binance: {price}"
        else:
            # Usamos Alpha Vantage (requiere API_KEY)
            api_key = "YOUR_ALPHA_VANTAGE_KEY"
            url = f"https://www.alphavantage.co/query?function=GLOBAL_QUOTE&symbol={symbol}&apikey={api_key}"
            resp = requests.get(url, timeout=10)
            resp.raise_for_status()
            data = resp.json()
            if "Global Quote" in data:
                price = data["Global Quote"].get("05. price")
                return f"Precio de {symbol} en Alpha Vantage: {price}"
            else:
                return f"Error al obtener datos de {symbol} (Alpha Vantage)."

    except Exception as e:
        err = f"Error en get_stock_price: {str(e)}"
        print(err)
        return err
```

